class OppModel:
    def __init__(self):
        self.raises = 0
        self.total = 0
        self.shove_count = 0     # times opp shoves (bet > 3x pot)
        self.postflop_hands = 0  # hands that reached post-flop

    def is_aggro(self, threshold=0.35):
        if self.total < 8:
            return False
        return self.raises / self.total > threshold

    def is_shove_bot(self):
        """Detect opponents who constantly all-in shove."""
        if self.total < 5:
            return False
        # 3. 24% Shove Loophole Fix: Lower threshold to 0.15 to catch frequent over-bettors
        return self.shove_count / self.total > 0.15


class Player(BaseBot):
    '''
    IIT-Pokerbots 2026: Asymmetric Information Bot
    Features: Perfect Memory CFR, Hard Raise Limits, L2 Norm Scaling, Vickrey Auctions.
    '''
    def __init__(self) -> None:
        self.hole_cards_eval7 = []
        self.history_str = ""
        self.current_street = "preflop"
        self.raises_this_street = 0
        
        self.opp = OppModel()
        self.revealed_opp_card = None
        self.opp_has_info = False
        self.auction_won = False
        self.auction_done = False
        self.we_bet_this_hand = False
        
        self.loser_cfr_table, self.flop_centroids, self.turn_centroids = self._decompress_table(MASTER_DATA)

    def _decompress_table(self, b64_string):
        # Unpacks the single string into the three required strategy components.            
        json_str = zlib.decompress(base64.b64decode(b64_string)).decode('utf-8')
        master_data = json.loads(json_str)
        
        # Convert CFR integer probabilities (0-100) back to floats (0.0-1.0)
        cfr_table = {k: [p / 100.0 for p in v] for k, v in master_data["cfr_table"].items()}
        
        return cfr_table, master_data["flop_centroids"], master_data["turn_centroids"]
        
    def on_hand_start(self, game_info: GameInfo, current_state: PokerState) -> None:
        self.revealed_opp_card = None
        self.opp_has_info = False
        self.auction_won = False
        self.auction_done = False
        self.we_bet_this_hand = False
        self.opp.total += 1
        
        hand = current_state.my_hand
        self._bucket = canonical_hand(hand[0], hand[1])
        self._preflop_eq = PREFLOP_EQUITY.get(self._bucket, 0.40)
        
        self.hole_cards_eval7 = [eval7.Card(c) for c in current_state.my_hand]
        self.flop_history_str = "11" # Default to check-check

    def on_hand_end(self, game_info: GameInfo, current_state: PokerState) -> None: pass

    def _update_auction_state(self, state):
        if self.auction_done:
            return
        if state.street in ('turn', 'river', 'flop'):
            if state.street == 'flop' and state.opp_revealed_cards:
                self.auction_done = True
                self.revealed_opp_card = eval7.Card(state.opp_revealed_cards[0])
                self.auction_won = True
            elif state.street in ('turn', 'river'):
                self.auction_done = True
                if state.opp_revealed_cards:
                    self.revealed_opp_card = eval7.Card(state.opp_revealed_cards[0])
                    self.auction_won = True
                else:
                    self.opp_has_info = True

    def get_move(self, game_info: GameInfo, current_state: PokerState):
        self._update_auction_state(current_state)
        
        street = current_state.street
        if street == 'pre-flop': return self._handle_preflop(current_state)
        elif street == 'auction': return self._handle_auction(current_state)
        
        if len(current_state.opp_revealed_cards) > 0:
            return self._handle_winner_state(current_state)
        else:
            return self._handle_loser_state(current_state)

    def _handle_preflop(self, current_state: PokerState):
        raw_eq = self._preflop_eq
        eq = raw_eq
        cost = current_state.cost_to_call
        pot = current_state.pot

        pot_odds = cost / (pot + cost) if cost > 0 else 0.0
        already_acted = current_state.my_wager > SMALL_BLIND
        
        # Adjust equity against unusually large raises (polarized ranges)
        if cost > 30 and cost > pot * 0.5:
             discount = min(0.25, 0.05 + (cost/max(1, pot)) * 0.1)
             eq = max(0.1, raw_eq - discount)

        # === Detect pre-flop all-in or massive shoves ===
        # 3. 24% Shove Loophole Fix: Use a dynamic threshold based on pot
        if cost > 250 or cost > pot * 1.5:
            self.opp.shove_count += 1
            
        if cost > 250 or cost > pot * 1.5:
            # Against shove bots, loosen up significantly to punish them
            shove_threshold = 0.60 if self.opp.is_shove_bot() else 0.75
            if eq >= shove_threshold:
                return ActionCall() if current_state.can_act(ActionCall) else ActionCheck()
            return ActionCheck() if current_state.can_act(ActionCheck) else ActionFold()

        # Handle opponent 3-bet / re-raise when we have already acted
        if already_acted and cost > 0:
            if eq >= 0.72:
                if current_state.can_act(ActionRaise):
                    lo, hi = current_state.raise_bounds
                    target = max(lo, min(hi, int(current_state.my_wager + cost * 2.5)))
                    return ActionRaise(target)
                return ActionCall() if current_state.can_act(ActionCall) else ActionCheck()
            elif eq >= pot_odds + 0.06:
                return ActionCall() if current_state.can_act(ActionCall) else ActionCheck()
            else:
                return ActionCheck() if current_state.can_act(ActionCheck) else ActionFold()

        # Big raise (not all-in)
        if cost > 200:
            if eq >= 0.65:
                return ActionCall() if current_state.can_act(ActionCall) else ActionCheck()
            return ActionCheck() if current_state.can_act(ActionCheck) else ActionFold()

        # Premium (top ~12%): Raise
        if eq >= 0.65:
            if current_state.can_act(ActionRaise):
                lo, hi = current_state.raise_bounds
                target = max(lo, min(hi, int(current_state.my_wager + 3.5 * BIG_BLIND)))
                return ActionRaise(target)
            return ActionCall() if current_state.can_act(ActionCall) else ActionCheck()

        # Good (top ~30%): Call if pot odds good
        if eq >= 0.52:
            if cost == 0:
                if current_state.can_act(ActionRaise) and random.random() < 0.15:
                    lo, hi = current_state.raise_bounds
                    return ActionRaise(max(lo, min(hi, int(current_state.my_wager + 2.5 * BIG_BLIND))))
                return ActionCheck()
            if eq >= pot_odds + 0.04:
                return ActionCall() if current_state.can_act(ActionCall) else ActionCheck()
            if current_state.can_act(ActionCheck):
                return ActionCheck()
            return ActionFold()

        # Marginal: Cheap calls only
        if eq >= 0.42:
            if cost == 0:
                return ActionCheck()
            if cost <= BIG_BLIND * 3 and eq >= pot_odds + 0.02:
                return ActionCall() if current_state.can_act(ActionCall) else ActionCheck()
            if current_state.can_act(ActionCheck):
                return ActionCheck()
            return ActionFold()

        # Trash
        if current_state.can_act(ActionCheck):
            return ActionCheck()
        return ActionFold()

    def _handle_auction(self, current_state: PokerState) -> ActionBid:
        board = [eval7.Card(str(c)) for c in current_state.board] if current_state.board else []
        eq = mc_equity(self.hole_cards_eval7, board, None, MC_SIMS_AUCTION)

        pot = current_state.pot
        my_chips = current_state.my_chips

        # Info value = equity_swing * expected_pot
        uncertainty = 1.0 - abs(eq - 0.5) * 2.0  # max at eq=0.5
        equity_swing = 0.10 + 0.15 * uncertainty  # 10-25% multiplier

        # Expected remaining pot value
        expected_pot = pot * 2.5

        # True value of info
        true_value = int(equity_swing * expected_pot)

        # 1. Auction Exploitation (Pot Inflation) Fix: Cap the bluff/trap bids 
        # so we don't bleed chips just because the opponent overbet pre-flop.
        rand_val = random.random()
        
        # Base bluff/trap on a conservative expected pot, capped at 200 chips
        safe_base = min(pot, 200)
        
        if rand_val < 0.05:
            # Bluff bid: weak hand/strong bid to represent premium hands
            bid = int(safe_base * random.uniform(0.4, 0.9))
        elif rand_val < 0.15:
            # Trap bid: strong hand/weak bid to under-represent and trap
            bid = int(pot * random.uniform(0.0, 0.15))
        else:
            # Standard noisy bid with much wider variance
            multiplier = random.uniform(0.8, 1.8)
            bid = int(true_value * multiplier)
            
        # Ensure bid stays somewhat sane during massive over-bluffs
        if eq > 0.8 and random.random() < 0.15:
            bid = int(true_value * random.uniform(1.3, 2.0))
        
        bid += random.choice([-2, -1, 0, 1, 2])
        
        final_bid = max(0, min(bid, my_chips))
        return ActionBid(final_bid)

    def _river_mdf_logic(self, current_state: PokerState):
        """
        TRACK B (River): Pure Math Heuristics (< 1ms).
        Executes when the offline CFR tree is truncated.
        """
        board_eval7 = [eval7.Card(c) for c in current_state.board]
        
        # 1. Calculate Absolute River Equity
        # Since there are no more community cards to deal, equity variance is much lower.
        # 400 iterations provides a highly accurate estimate in under 0.5ms.
        equity = self._fast_equity(self.hole_cards_eval7, board_eval7, iterations=400)
        
        facing_bet = not current_state.can_act(ActionCheck)
        
        # ---------------------------------------------------------------------
        # SCENARIO A: Defense (We are facing a bet)
        # ---------------------------------------------------------------------
        if facing_bet:
            # Minimum Defense Frequency (MDF) Proxy
            # To stop the omniscient opponent from bluffing 100% of the time, we must call.
            # However, because they see our card, we cannot call with marginal "bluff catchers".
            # We use a strict > 0.60 absolute equity threshold. This mathematically ensures 
            # we are only defending with the absolute top tier of our surviving range.
            
            if equity > 0.60:
                return ActionCall()
                
            return ActionFold() if current_state.can_act(ActionFold) else ActionCheck()
            
        # ---------------------------------------------------------------------
        # SCENARIO B: Offense (We act first OR opponent checked to us)
        # ---------------------------------------------------------------------
        else:
            # Split-Reality Value Betting
            # The opponent has X-ray vision on one card. If we bet, they will play perfectly,
            # instantly folding their trash and only calling with hands that beat us.
            # Therefore, we ONLY bet if our hand is a near-absolute monster (> 85% equity).
            
            if equity > 0.85 and current_state.can_act(ActionRaise):
                pot = sum(current_state.pot) if isinstance(current_state.pot, list) else current_state.pot
                min_r, max_r = current_state.raise_bounds
                
                # We map to our "raise_50" sizing logic to extract safe value
                target = int(pot * 0.5)
                
                # Clamp the bet to engine bounds to prevent illegal move penalties
                target = max(min_r, min(target, max_r))
                return ActionRaise(target)
                
            # If we don't have a monster, we happily check and take the free showdown
            return ActionCheck()

    def _post_flop_heuristic(self, s: PokerState):
        board = [eval7.Card(str(c)) for c in s.board] if s.board else []
        opp_k = [self.revealed_opp_card] if self.revealed_opp_card else None
        eq = get_equity(self.hole_cards_eval7, board, opp_k)

        pot = sum(s.pot) if isinstance(s.pot, list) else s.pot
        cost = s.cost_to_call
        my_chips = s.my_chips
        eff_stack = min(my_chips, s.opp_chips) if hasattr(s, 'opp_chips') else my_chips
        
        streets = {'flop': 3, 'turn': 2, 'river': 1}.get(s.street, 1)

        self.opp.postflop_hands += 1
        if cost > pot * 2.5:
            self.opp.shove_count += 1

        is_shove_bot = self.opp.is_shove_bot()

        bet_to_pot = cost / max(1, pot - cost) if cost > 0 else 0.0
        pot_odds = cost / (pot + cost) if cost > 0 else 0.0

        # --- FACING A BET ---
        if cost > 0:
            required_eq = pot_odds
            
            if bet_to_pot <= 0.4:
                required_eq += 0.05
            elif bet_to_pot <= 0.8:
                required_eq += 0.10
            elif bet_to_pot <= 1.5:
                required_eq += 0.20
            elif bet_to_pot <= 2.5:
                required_eq += 0.30
            else:
                required_eq += 0.40  # Massive overbet

            if self.opp_has_info and not self.auction_won:
                r1, r2 = self.hole_cards_eval7[0].rank, self.hole_cards_eval7[1].rank
                low_r = min(r1, r2)
                high_r = max(r1, r2)
                
                if high_r >= 10 and low_r <= 5:
                    required_eq += 0.05
                elif low_r >= 8:
                    required_eq += 0.20
                else:
                    required_eq += 0.10
                
            required_eq = min(0.95, required_eq)
            
            if is_shove_bot and bet_to_pot > 1.0:
                required_eq -= 0.10

            if eq >= required_eq:
                if eq >= 0.90 and bet_to_pot <= 1.0 and s.can_act(ActionRaise):
                    if pot < 1000 or eq >= 0.95:
                        lo, hi = s.raise_bounds
                        amt = max(lo, min(hi, int(s.my_wager + pot * 0.8)))
                        self.we_bet_this_hand = True
                        return ActionRaise(amt)
                
                return ActionCall() if s.can_act(ActionCall) else ActionCheck()
                
            return ActionCheck() if s.can_act(ActionCheck) else ActionFold()

        # --- WE ARE FIRST TO ACT ---
        if s.can_act(ActionRaise):
            lo, hi = s.raise_bounds

            if eq >= 0.88 and random.random() < 0.25:
                return ActionCheck()

            if eq >= 0.82:
                if random.random() < 0.10:
                    return ActionCall() if s.can_act(ActionCall) else ActionCheck()
                if s.can_act(ActionRaise):
                    lo, hi = s.raise_bounds
                    geo = geometric_bet_size(pot + cost, eff_stack, streets)
                    if streets == 1:
                        geo = eff_stack if eq >= 0.95 else int(pot * 1.5)
                    amt = max(lo, min(hi, int(s.my_wager + geo + cost)))
                    self.we_bet_this_hand = True
                    return ActionRaise(amt)
                return ActionCall() if s.can_act(ActionCall) else ActionCheck()

            if eq <= 0.30:
                if s.can_act(ActionRaise) and cost == 0 and random.random() < 0.05:
                    lo, hi = s.raise_bounds
                    amt = max(lo, min(hi, int(s.my_wager + pot * 0.70)))
                    self.we_bet_this_hand = True
                    return ActionRaise(amt)
                if s.can_act(ActionCheck):
                    return ActionCheck()
                return ActionFold()
                
            if eq >= 0.75:
                if is_shove_bot:
                    bet = int(pot * random.uniform(0.35, 0.45))
                else:
                    bet = int(pot * random.uniform(0.55, 0.75))
                amt = max(lo, min(hi, int(s.my_wager + bet)))
                self.we_bet_this_hand = True
                return ActionRaise(amt)
                
            if eq >= 0.60:
                if is_shove_bot:
                    return ActionCheck() 
                if self.auction_won or not self.opp_has_info:
                    bet = int(pot * random.uniform(0.30, 0.50))
                    amt = max(lo, min(hi, int(s.my_wager + bet)))
                    self.we_bet_this_hand = True
                    return ActionRaise(amt)
                    
            if (not is_shove_bot
                    and 0.20 < eq < 0.50
                    and not self.opp_has_info
                    and random.random() < 0.10):
                bet = int(pot * random.uniform(0.40, 0.65))
                amt = max(lo, min(hi, int(s.my_wager + bet)))
                self.we_bet_this_hand = True
                return ActionRaise(amt)

        return ActionCheck()

    def _handle_winner_state(self, current_state: PokerState):
        return self._post_flop_heuristic(current_state)
   
    # --------------------------------------
    # ------ SORTED ------------------------
    # --------------------------------------
    def _handle_loser_state(self, current_state: PokerState):
        """TRACK B: Perfect Memory CFR Lookup."""
        street = current_state.street
        
        if street in ['flop', 'turn']:
            board_eval7 = [eval7.Card(c) for c in current_state.board]
            
            # 1. Scaled Live Features (Fixes the Bucket 259 scaling bug)
            live_eq = self._fast_equity(self.hole_cards_eval7, board_eval7, 500) * 1000.0
            live_wet = self._calculate_board_wetness(board_eval7) * 1000.0
            bucket_id = self._get_closest_centroid([live_eq, live_wet], street)
            
            # 2. Positional Mapping
            facing_bet = not current_state.can_act(ActionCheck)
            hist_suffix = "2" if facing_bet else "1"
            
            abstract_state = ""
            if street == 'flop':
                abstract_state = f"f{bucket_id}_{hist_suffix}"
            else:
                # Perfect Turn Memory (e.g., t111_121t2)
                abstract_state = f"t{bucket_id}_{self.flop_history_str}t{hist_suffix}"
            
            # 3. Fetch Strategy
            strategy = self.loser_cfr_table.get(abstract_state)
            
            if strategy is None:
                print(f"[CFR MISS] Missing '{abstract_state}'. Using heuristic fallback...")
                return self._post_flop_heuristic(current_state)
            else:
                print(f"[CFR HIT] Found '{abstract_state}' -> {strategy}")
                action, act_char = self._sample_action(strategy, current_state)
                
            # 4. Perfect Memory Recorder
            # If we are on the flop, we must store what happened so the Turn knows the exact path.
            if street == 'flop':
                if act_char == '1': # We checked or called
                    self.flop_history_str = hist_suffix + "1"
                elif act_char in ['2', '3']: # We raised
                    # If we raise, the opponent MUST call ("1") for the game to reach the Turn.
                    self.flop_history_str = hist_suffix + act_char + "1"
                    
            return action
            
        elif street == 'river':
            return self._river_mdf_logic(current_state)


    def _sample_action(self, strategy: list, current_state: PokerState):
        """Converts probabilities into engine actions AND character codes for perfect memory."""
        actions = ["fold", "call", "raise_50", "raise_200"]
        chosen = random.choices(actions, weights=strategy, k=1)[0]
        
        # 1. Fold Branch
        if chosen == "fold" and current_state.can_act(ActionFold):
            # Must return the action AND the "0" string
            return ActionFold(), "0"
            
        # 2. Raise Branch
        if "raise" in chosen and current_state.can_act(ActionRaise):
            min_raise, max_raise = current_state.raise_bounds
            pot = sum(current_state.pot) if isinstance(current_state.pot, list) else current_state.pot
            
            target = 0
            act_char = "2" # Default to 50% raise char
            
            if chosen == "raise_50": 
                target = int(pot * 0.5)
                act_char = "2"
            elif chosen == "raise_200": 
                target = int(pot * 2.0)
                act_char = "3"
            
            # Mathematically clamp the bet to legal engine bounds
            target = max(min_raise, min(target, max_raise))
            
            # Must return the action AND the correct "2" or "3" string
            return ActionRaise(target), act_char
            
        # 3. Call/Check Fallback Branch
        if current_state.can_act(ActionCall):
            # Must return the action AND the "1" string
            return ActionCall(), "1"
        else:
            # Must return the action AND the "1" string
            return ActionCheck(), "1"

